mapper.select:
select r.*, u.username, u.name, u.phone from user_real_name_auth r left join user u on r.user_id = u.id
and r.status = #{status}
order by r.create_time desc

mapper.update:
update user_real_name_auth
set status = #{status},
    audit_remark = #{auditRemark},
    audit_time = #{auditTime}
where id = #{id}

mapper.select:
select d.*, u.username, u.name, u.phone from user_driver_license_auth d left join user u on d.user_id = u.id
and d.status = #{status}
order by d.create_time desc

mapper.update:
update user_driver_license_auth
set status = #{status},
    audit_remark = #{auditRemark},
    audit_time = #{auditTime}
where id = #{id}

mapper.select:
select * from ( select 'real_name' as authType, r.id, r.user_id as userId, u.username, u.name as userRealName, u.phone, r.real_name as authName, r.id_number as authNumber, r.id_front_image as frontImage, r.id_back_image as backImage, r.status, r.audit_remark as auditRemark, r.audit_time as auditTime, r.create_time as createTime, null as vehicleType, null as validStart, null as validEnd from user_real_name_auth r left join user u on r.user_id = u.id
union all
select 'driver_license' as authType, d.id, d.user_id as userId, u.username, u.name as userRealName, u.phone, d.driver_name as authName, d.license_number as authNumber, d.license_front_image as frontImage, d.license_back_image as backImage, d.status, d.audit_remark as auditRemark, d.audit_time as auditTime, d.create_time as createTime, d.vehicle_type as vehicleType, d.valid_start as validStart, d.valid_end as validEnd from user_driver_license_auth d left join user u on d.user_id = u.id
) t
and t.status = #{status}
and t.authType = #{authType}
order by t.createTime desc

mapper.update:
update user


        real_name_verified = #{status}


        driver_license_verified = #{status}


where id = #{userId}
